const db = require('../../db');

/**
 * Normalize tags input to an array of lowercase trimmed strings.
 * Accepts comma-separated string or array of strings.
 * @param {string|string[]} tags
 * @returns {string[]}
 */
function normalizeTags(tags) {
  if (!tags) return [];
  if (Array.isArray(tags)) {
    return tags
      .filter(t => typeof t === 'string' && t.trim().length > 0)
      .map(t => t.toLowerCase().trim());
  }
  if (typeof tags === 'string') {
    return tags
      .split(',')
      .map(t => t.toLowerCase().trim())
      .filter(t => t.length > 0);
  }
  return [];
}

/**
 * Fetch problems with optional filters: difficulty, limit, tags.
 * Tags filter is case-insensitive and matches problems having all specified tags.
 * Returns problems sorted by stable criteria (e.g., id ascending).
 * Also returns metadata including normalized tags filter.
 *
 * @param {Object} options
 * @param {string} [options.difficulty]
 * @param {number} [options.limit]
 * @param {string|string[]} [options.tags]
 * @returns {Promise<{problems: Object[], metadata: Object}>}
 */
async function getProblems({ difficulty, limit, tags } = {}) {
  const normalizedTags = normalizeTags(tags);

  // Base query
  let query = 'SELECT * FROM problems';
  const conditions = [];
  const params = [];

  if (difficulty) {
    conditions.push('difficulty = $' + (params.length + 1));
    params.push(difficulty);
  }

  if (normalizedTags.length > 0) {
    // We assume problems.tags is a JSONB array of strings in DB
    // We want problems that have all tags in normalizedTags
    // Use Postgres @> operator for array containment
    conditions.push('tags @> $' + (params.length + 1));
    params.push(normalizedTags);
  }

  if (conditions.length > 0) {
    query += ' WHERE ' + conditions.join(' AND ');
  }

  query += ' ORDER BY id ASC';

  if (limit && Number.isInteger(limit) && limit > 0) {
    query += ' LIMIT $' + (params.length + 1);
    params.push(limit);
  }

  const { rows } = await db.query(query, params);

  return {
    problems: rows,
    metadata: {
      tags: normalizedTags
    }
  };
}

module.exports = {
  getProblems
};
